func parsePodcastScript(path string) (podcastEpisode, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return podcastEpisode{}, err
	}
	raw := string(data)
	hash := sha256.Sum256(data)
	episode := podcastEpisode{
		Model:        "eleven_v3",
		OutputFormat: "mp3_44100_192",
		Loudness:     -16,
		Cast:         map[string]string{},
		Music:        map[string]podcastMusic{},
		SourceHash:   hex.EncodeToString(hash[:]),
	}
	body := raw
	if strings.HasPrefix(raw, "---") {
		parts := strings.SplitN(raw, "---", 3)
		if len(parts) < 3 {
			return podcastEpisode{}, usageErr(fmt.Errorf("unterminated YAML front matter"))
		}
		if err := parsePodcastFrontMatter(parts[1], &episode); err != nil {
			return podcastEpisode{}, err
		}
		body = parts[2]
	}
	if err := parsePodcastBody(body, &episode); err != nil {
		return podcastEpisode{}, err
	}
	if len(episode.Cast) == 0 {
		return podcastEpisode{}, usageErr(fmt.Errorf("script cast is empty"))
	}
	for i := range episode.Segments {
		episode.Segments[i].Index = i
	}
	return episode, nil
}

func parsePodcastFrontMatter(src string, episode *podcastEpisode) error {
	section := ""
	for _, rawLine := range strings.Split(src, "\n") {
		line := strings.TrimRight(rawLine, " \t")
		trimmed := strings.TrimSpace(line)
		if trimmed == "" || strings.HasPrefix(trimmed, "#") {
			continue
		}
		indented := len(line) > 0 && (line[0] == ' ' || line[0] == '\t')
		if !indented && strings.HasSuffix(trimmed, ":") {
			section = strings.TrimSuffix(trimmed, ":")
			continue
		}
		key, value, ok := strings.Cut(trimmed, ":")
		if !ok {
			return usageErr(fmt.Errorf("invalid front-matter line %q", trimmed))
		}
		key = strings.TrimSpace(key)
		value = cleanPodcastScalar(value)
		if indented {
			switch section {
			case "cast":
				episode.Cast[key] = value
			case "music":
				episode.Music[key] = parsePodcastMusic(value)
			}
			continue
		}
		section = ""
		switch key {
		case "title":
			episode.Title = value
		case "episode":
			episode.Episode = value
		case "language":
			episode.Language = value
		case "model":
			episode.Model = value
		case "output_format":
			episode.OutputFormat = value
		case "loudness":
			if v, err := strconv.ParseFloat(value, 64); err == nil {
				episode.Loudness = v
			}
		}
	}
	return nil
}

func parsePodcastMusic(value string) podcastMusic {
	fields := parseInlineMap(value)
	music := podcastMusic{Prompt: fields["prompt"], Path: fields["path"]}
	if seconds, err := strconv.ParseFloat(fields["seconds"], 64); err == nil {
		music.Seconds = seconds
	}
	if duck, err := strconv.ParseFloat(fields["duck_db"], 64); err == nil {
		music.DuckDB = duck
	}
	if music.Prompt == "" && !strings.HasPrefix(value, "{") {
		music.Prompt = cleanPodcastScalar(value)
	}
	return music
}

func parsePodcastBody(src string, episode *podcastEpisode) error {
	var turns []podcastTurn
	activeBed := ""
	flushVoice := func() {
		if len(turns) == 0 {
			return
		}
		textParts := make([]string, 0, len(turns))
		for _, turn := range turns {
			textParts = append(textParts, turn.Text)
		}
		episode.Segments = append(episode.Segments, podcastSegment{
			Kind:    "voice",
			Turns:   append([]podcastTurn(nil), turns...),
			BedName: activeBed,
			Text:    strings.Join(textParts, "\n"),
		})
		turns = nil
	}
	for lineNo, rawLine := range strings.Split(src, "\n") {
		trimmed := strings.TrimSpace(rawLine)
		if trimmed == "" || strings.HasPrefix(trimmed, "#") {
			continue
		}
		if strings.HasPrefix(trimmed, "[") && strings.HasSuffix(trimmed, "]") {
			cue := strings.TrimSuffix(strings.TrimPrefix(trimmed, "["), "]")
			switch {
			case cue == "intro":
				flushVoice()
				episode.Segments = append(episode.Segments, podcastSegment{Kind: "intro", MusicName: "intro"})
			case cue == "outro":
				flushVoice()
				episode.Segments = append(episode.Segments, podcastSegment{Kind: "outro", MusicName: "outro"})
				activeBed = ""
			case strings.HasPrefix(cue, "music:"):
				flushVoice()
				name := strings.TrimSpace(strings.TrimPrefix(cue, "music:"))
				if name == "stop" {
					activeBed = ""
				} else if name == "" {
					return usageErr(fmt.Errorf("line %d: [music:] requires a music name", lineNo+1))
				} else {
					activeBed = name
				}
			case strings.HasPrefix(cue, "sfx:"):
				flushVoice()
				prompt, seconds := parseSFXCue(strings.TrimSpace(strings.TrimPrefix(cue, "sfx:")))
				episode.Segments = append(episode.Segments, podcastSegment{Kind: "sfx", SFXPrompt: prompt, SFXSeconds: seconds})
			default:
				return usageErr(fmt.Errorf("line %d: unknown cue [%s]", lineNo+1, cue))
			}
			continue
		}
		speaker, text, ok := strings.Cut(trimmed, ":")
		if !ok || strings.TrimSpace(speaker) == "" || strings.TrimSpace(text) == "" {
			return usageErr(fmt.Errorf("line %d: expected SPEAKER: text or a bracket cue", lineNo+1))
		}
		speaker = strings.TrimSpace(speaker)
		if _, ok := episode.Cast[speaker]; !ok {
			return usageErr(fmt.Errorf("line %d: speaker %q is not in cast", lineNo+1, speaker))
		}
		text = strings.TrimSpace(text)
		turns = append(turns, podcastTurn{Speaker: speaker, Text: text})
		episode.TextChars += len([]rune(text))
	}
	flushVoice()
	return validatePodcastEpisode(*episode)
}

func validatePodcastEpisode(episode podcastEpisode) error {
	for _, segment := range episode.Segments {
		switch segment.Kind {
		case "intro", "outro":
			if _, ok := episode.Music[segment.MusicName]; !ok {
				return usageErr(fmt.Errorf("%s cue requires music.%s in front matter or --%s override", segment.Kind, segment.MusicName, segment.Kind))
			}
		case "voice":
			if segment.BedName != "" {
				if _, ok := episode.Music[segment.BedName]; !ok {
					return usageErr(fmt.Errorf("music bed %q is not defined", segment.BedName))
				}
			}
		}
	}
	return nil
}

func applyPodcastOverrides(episode *podcastEpisode, opts podcastProduceOptions) {
	for _, assignment := range opts.CastOverrides {
		speaker, voice, ok := strings.Cut(assignment, "=")
		if ok {
			episode.Cast[strings.TrimSpace(speaker)] = strings.TrimSpace(voice)
		}
	}
	if opts.IntroOverride != "" {
		episode.Music["intro"] = podcastMusic{Prompt: opts.IntroOverride, Path: localPathIfExists(opts.IntroOverride), Seconds: episode.Music["intro"].Seconds}
	}
	if opts.OutroOverride != "" {
		episode.Music["outro"] = podcastMusic{Prompt: opts.OutroOverride, Path: localPathIfExists(opts.OutroOverride), Seconds: episode.Music["outro"].Seconds}
	}
	if opts.Model != "" {
		episode.Model = opts.Model
	}
	if opts.OutputFormat != "" {
		episode.OutputFormat = opts.OutputFormat
	}
	if opts.Loudness != 0 {
		episode.Loudness = opts.Loudness
	}
}

func estimatePodcast(episode podcastEpisode) podcastEstimate {
	musicNames := map[string]bool{}
	sfxCount := 0
	for _, segment := range episode.Segments {
		if segment.Kind == "intro" || segment.Kind == "outro" {
			musicNames[segment.MusicName] = true
		}
		if segment.BedName != "" {
			musicNames[segment.BedName] = true
		}
		if segment.Kind == "sfx" {
			sfxCount++
		}
	}
	return podcastEstimate{VoiceCharacters: episode.TextChars, MusicGenerations: len(musicNames), SFXGenerations: sfxCount}
}

func resolvePodcastCast(c *client.Client, cast map[string]string) (map[string]elevenVoice, error) {
	out := make(map[string]elevenVoice, len(cast))
	keys := make([]string, 0, len(cast))
	for speaker := range cast {
		keys = append(keys, speaker)
	}
	sort.Strings(keys)
	for _, speaker := range keys {
		voice, err := resolveVoice(c, cast[speaker])
		if err != nil {
			return nil, err
		}
		out[speaker] = voice
	}
	return out, nil
}

func fillPodcastBudget(c *client.Client, estimate *podcastEstimate) error {
	data, err := c.Get("/v1/user/subscription", nil)
	if err != nil {
		return err
	}
	var sub struct {
		CharacterCount int `json:"character_count"`
		CharacterLimit int `json:"character_limit"`
	}
	if err := json.Unmarshal(extractResponseData(data), &sub); err != nil {
		return err
	}
	estimate.CharacterCount = sub.CharacterCount
	estimate.CharacterLimit = sub.CharacterLimit
	estimate.RemainingCharacters = sub.CharacterLimit - sub.CharacterCount
	estimate.OverCharacterBudget = estimate.RemainingCharacters >= 0 && estimate.VoiceCharacters > estimate.RemainingCharacters
	return nil
}

func generatePodcastArtifacts(c *client.Client, tools ffmpegTools, flags *rootFlags, opts podcastProduceOptions, episode *podcastEpisode, voices map[string]elevenVoice, modelID string, manifest *podcastManifest) error {
	segmentsDir := filepath.Join(opts.OutDir, "segments")
	assetsDir := filepath.Join(opts.OutDir, "assets")
	if err := os.MkdirAll(segmentsDir, 0o755); err != nil {
		return err
	}
	if err := os.MkdirAll(assetsDir, 0o755); err != nil {
		return err
	}
	generatedMusic := map[string]string{}
	for i := range episode.Segments {
		segment := &episode.Segments[i]
		switch segment.Kind {
		case "voice":
			path := filepath.Join(segmentsDir, fmt.Sprintf("%02d-voice.%s", i, extensionForOutputFormat(episode.OutputFormat)))
			hash := hashPodcastSegment(*segment, modelID, episode.OutputFormat)
			if opts.Resume && fileExists(path) {
				segment.Artifact = path
				segment.Hash = hash
			} else {
				data, err := renderPodcastVoice(c, *segment, voices, modelID, episode.Language, episode.OutputFormat)
				if err != nil {
					return classifyAPIError(err, flags)
				}
				if err := writeAtomicFile(path, data); err != nil {
					return err
				}
				if opts.Isolate {
					isolated, err := isolatePodcastAudio(c, path)
					if err != nil {
						return classifyAPIError(err, flags)
					}
					if err := writeAtomicFile(path, isolated); err != nil {
						return err
					}
				}
				segment.Artifact = path
				segment.Bytes = len(data)
				segment.Hash = hash
			}
			duration, _ := ffprobeDuration(tools.FFprobe, path)
			segment.DurationSec = duration
			manifest.Artifacts = append(manifest.Artifacts, podcastArtifact{Kind: "voice", Path: path, Bytes: fileSize(path)})
		case "intro", "outro":
			path, err := ensurePodcastMusic(c, flags, opts, episode.Music[segment.MusicName], segment.MusicName, assetsDir, episode.OutputFormat, generatedMusic)
			if err != nil {
				return err
			}
			segment.Artifact = path
			segment.Bytes = fileSize(path)
			duration, _ := ffprobeDuration(tools.FFprobe, path)
			segment.DurationSec = duration
			manifest.Artifacts = append(manifest.Artifacts, podcastArtifact{Kind: "music", Path: path, Bytes: fileSize(path)})
		case "sfx":
			path := filepath.Join(assetsDir, fmt.Sprintf("sfx-%02d.%s", i, extensionForOutputFormat(episode.OutputFormat)))
			if !(opts.Resume && fileExists(path)) {
				data, err := generatePodcastSFX(c, *segment, episode.OutputFormat)
				if err != nil {
					return classifyAPIError(err, flags)
				}
				if err := writeAtomicFile(path, data); err != nil {
					return err
				}
			}
			segment.Artifact = path
			segment.Bytes = fileSize(path)
			duration, _ := ffprobeDuration(tools.FFprobe, path)
			segment.DurationSec = duration
			manifest.Artifacts = append(manifest.Artifacts, podcastArtifact{Kind: "sfx", Path: path, Bytes: fileSize(path)})
		}
		if segment.BedName != "" {
			if _, err := ensurePodcastMusic(c, flags, opts, episode.Music[segment.BedName], segment.BedName, assetsDir, episode.OutputFormat, generatedMusic); err != nil {
				return err
			}
		}
	}
	return nil
}

func renderPodcastVoice(c *client.Client, segment podcastSegment, voices map[string]elevenVoice, modelID, language, outputFormat string) ([]byte, error) {
	params := map[string]string{"output_format": outputFormat}
	if len(segment.Turns) == 1 {
		turn := segment.Turns[0]
		body := map[string]any{"text": turn.Text, "model_id": modelID}
		if language != "" {
			body["language_code"] = language
		}
		returnData, _, err := c.PostWithParams("/v1/text-to-speech/"+voices[turn.Speaker].VoiceID, params, body)
		return returnData, err
	}
	inputs := make([]map[string]any, 0, len(segment.Turns))
	for _, turn := range segment.Turns {
		inputs = append(inputs, map[string]any{"text": turn.Text, "voice_id": voices[turn.Speaker].VoiceID})
	}
	body := map[string]any{"inputs": inputs, "model_id": modelID}
	if language != "" {
		body["language_code"] = language
	}
	data, _, err := c.PostWithParams("/v1/text-to-dialogue", params, body)
	return data, err
}

func isolatePodcastAudio(c *client.Client, path string) ([]byte, error) {
	data, _, err := c.PostMultipartWithParams("/v1/audio-isolation", nil, map[string]string{"file_format": "other"}, map[string]string{"audio": path})
	return data, err
}

func ensurePodcastMusic(c *client.Client, flags *rootFlags, opts podcastProduceOptions, music podcastMusic, name, assetsDir, outputFormat string, generated map[string]string) (string, error) {
	if path := localPathIfExists(music.Path); path != "" {
		return path, nil
	}
	if path := localPathIfExists(music.Prompt); path != "" {
		return path, nil
	}
	if existing := generated[name]; existing != "" {
		return existing, nil
	}
	path := filepath.Join(assetsDir, fmt.Sprintf("music-%s.%s", sanitizeFilename(name), extensionForOutputFormat(outputFormat)))
	if opts.Resume && fileExists(path) {
		generated[name] = path
		return path, nil
	}
	seconds := music.Seconds
	if seconds <= 0 {
		seconds = 10
	}
	lengthMS := int(seconds * 1000)
	if lengthMS < 3000 {
		lengthMS = 3000
	}
	if lengthMS > 600000 {
		lengthMS = 600000
	}
	body := map[string]any{
		"prompt":             music.Prompt,
		"music_length_ms":    fmt.Sprintf("%d", lengthMS),
		"model_id":           "music_v1",
		"force_instrumental": true,
	}
	data, _, err := c.PostWithParams("/v1/music", map[string]string{"output_format": outputFormat}, body)
	if err != nil {
		return "", classifyAPIError(err, flags)
	}
	if err := writeAtomicFile(path, data); err != nil {
		return "", err
	}
	generated[name] = path
	return path, nil
}

func generatePodcastSFX(c *client.Client, segment podcastSegment, outputFormat string) ([]byte, error) {
	seconds := segment.SFXSeconds
	if seconds <= 0 {
		seconds = 2
	}
	if seconds > 30 {
		seconds = 30
	}
	if seconds < 0.5 {
		seconds = 0.5
	}
	body := map[string]any{
		"text":             segment.SFXPrompt,
		"duration_seconds": fmt.Sprintf("%.1f", seconds),
		"prompt_influence": "0.3",
		"loop":             false,
		"model_id":         "eleven_text_to_sound_v2",
	}
	data, _, err := c.PostWithParams("/v1/sound-generation", map[string]string{"output_format": outputFormat}, body)
	return data, err
}

func alignPodcastVoiceSegments(c *client.Client, outDir string, episode podcastEpisode) ([]podcastArtifact, error) {
	var artifacts []podcastArtifact
	alignDir := filepath.Join(outDir, "alignment")
	for _, segment := range episode.Segments {
		if segment.Kind != "voice" || segment.Artifact == "" {
			continue
		}
		path := filepath.Join(alignDir, fmt.Sprintf("%02d-forced-alignment.json", segment.Index))
		data, _, err := c.PostMultipartWithParams("/v1/forced-alignment", nil, map[string]string{"text": segment.Text}, map[string]string{"file": segment.Artifact})
		if err != nil {
			return artifacts, err
		}
		if err := writeAtomicFile(path, []byte(extractResponseData(data))); err != nil {
			return artifacts, err
		}
		artifacts = append(artifacts, podcastArtifact{Kind: "forced_alignment", Path: path, Bytes: fileSize(path)})
	}
	return artifacts, nil
}

func transcribePodcastMix(c *client.Client, outDir, audioPath, language string) ([]podcastArtifact, error) {
	fields := map[string]string{
		"model_id": "scribe_v1",
		"diarize":  "true",
	}
	if language != "" {
		fields["language_code"] = language
	}
	data, _, err := c.PostMultipartWithParams("/v1/speech-to-text", nil, fields, map[string]string{"file": audioPath})
	if err != nil {
		return nil, err
	}
	raw := extractResponseData(data)
	jsonPath := filepath.Join(outDir, "transcript.json")
	if err := writeAtomicFile(jsonPath, []byte(raw)); err != nil {
		return nil, err
	}
	if text := transcriptTextFromSTT(raw); text != "" {
		if err := writeAtomicFile(filepath.Join(outDir, "transcript.txt"), []byte(text+"\n")); err != nil {
			return nil, err
		}
	}
	return []podcastArtifact{{Kind: "speech_to_text", Path: jsonPath, Bytes: fileSize(jsonPath)}}, nil
}

func transcriptTextFromSTT(data json.RawMessage) string {
	var obj map[string]any
	if err := json.Unmarshal(data, &obj); err != nil {
		return ""
	}
	if text, _ := obj["text"].(string); text != "" {
		return text
	}
	if text, _ := obj["transcript"].(string); text != "" {
		return text
	}
	return ""
}

func podcastMixItems(episode podcastEpisode) ([]podcastMixItem, error) {
	var items []podcastMixItem
	for _, segment := range episode.Segments {
		if segment.Artifact == "" {
			continue
		}
		item := podcastMixItem{Kind: segment.Kind, Path: segment.Artifact, DurationSeconds: segment.DurationSec}
		if segment.Kind == "voice" && segment.BedName != "" {
			music := episode.Music[segment.BedName]
			item.BedPath = localPathIfExists(music.Path)
			if item.BedPath == "" {
				item.BedPath = filepath.Join(filepath.Dir(filepath.Dir(segment.Artifact)), "assets", fmt.Sprintf("music-%s.%s", sanitizeFilename(segment.BedName), extensionForOutputFormat(episode.OutputFormat)))
			}
		}
		items = append(items, item)
	}
	if len(items) == 0 {
		return nil, fmt.Errorf("no generated audio artifacts found")
	}
	return items, nil
}

func buildPodcastChapters(episode podcastEpisode) []podcastChapter {
	var chapters []podcastChapter
	current := 0.0
	for _, segment := range episode.Segments {
		switch segment.Kind {
		case "intro":
			chapters = append(chapters, podcastChapter{StartTime: current, Title: "Intro"})
		case "voice":
			if len(chapters) == 0 {
				chapters = append(chapters, podcastChapter{StartTime: current, Title: episode.Title})
			}
		case "outro":
			chapters = append(chapters, podcastChapter{StartTime: current, Title: "Outro"})
		}
		current += segment.DurationSec
	}
	return chapters
}

func writePodcastTextOutputs(outDir string, episode podcastEpisode, chapters []podcastChapter) error {
	var transcript strings.Builder
	var srt strings.Builder
	idx := 1
	current := 0.0
	for _, segment := range episode.Segments {
		if segment.Kind != "voice" {
			current += segment.DurationSec
			continue
		}
		for _, turn := range segment.Turns {
			fmt.Fprintf(&transcript, "%s: %s\n", turn.Speaker, turn.Text)
		}
		fmt.Fprintf(&srt, "%d\n%s --> %s\n%s\n\n", idx, formatSRTTime(current), formatSRTTime(current+segment.DurationSec), segment.Text)
		idx++
		current += segment.DurationSec
	}
	if err := writeAtomicFile(filepath.Join(outDir, "transcript.txt"), []byte(transcript.String())); err != nil {
		return err
	}
	if err := writeAtomicFile(filepath.Join(outDir, "transcript.srt"), []byte(srt.String())); err != nil {
		return err
	}
	return writeJSONFile(filepath.Join(outDir, "chapters.json"), chapters)
}

func parseInlineMap(value string) map[string]string {
	out := map[string]string{}
	value = strings.TrimSpace(value)
	value = strings.TrimPrefix(value, "{")
	value = strings.TrimSuffix(value, "}")
	for _, part := range splitPodcastInlineFields(value) {
		key, val, ok := strings.Cut(part, ":")
		if !ok {
			continue
		}
		out[strings.TrimSpace(key)] = cleanPodcastScalar(val)
	}
	return out
}

func splitPodcastInlineFields(value string) []string {
	var fields []string
	var current strings.Builder
	quote := rune(0)
	for _, r := range value {
		switch {
		case quote != 0:
			current.WriteRune(r)
			if r == quote {
				quote = 0
			}
		case r == '\'' || r == '"':
			quote = r
			current.WriteRune(r)
		case r == ',':
			if field := strings.TrimSpace(current.String()); field != "" {
				fields = append(fields, field)
			}
			current.Reset()
		default:
			current.WriteRune(r)
		}
	}
	if field := strings.TrimSpace(current.String()); field != "" {
		fields = append(fields, field)
	}
	return fields
}

func cleanPodcastScalar(value string) string {
	value = strings.TrimSpace(value)
	if idx := strings.Index(value, " #"); idx >= 0 {
		value = strings.TrimSpace(value[:idx])
	}
	value = strings.Trim(value, `"'`)
	return value
}

func parseSFXCue(value string) (string, float64) {
	parts := strings.Split(value, ",")
	prompt := strings.TrimSpace(parts[0])
	seconds := 2.0
	if len(parts) > 1 {
		raw := strings.TrimSuffix(strings.TrimSpace(parts[1]), "s")
		if parsed, err := strconv.ParseFloat(raw, 64); err == nil {
			seconds = parsed
		}
	}
	return prompt, seconds
}

func hashPodcastSegment(segment podcastSegment, modelID, outputFormat string) string {
	h := sha256.Sum256([]byte(segment.Text + "|" + segment.BedName + "|" + modelID + "|" + outputFormat))
	return hex.EncodeToString(h[:])
}

func localPathIfExists(value string) string {
	if value == "" {
		return ""
	}
	if _, err := os.Stat(value); err == nil {
		return value
	}
	return ""
}

func sanitizeFilename(value string) string {
	value = strings.ToLower(value)
	re := regexp.MustCompile(`[^a-z0-9._-]+`)
	value = re.ReplaceAllString(value, "-")
	return strings.Trim(value, "-")
}

func writeAtomicFile(path string, data []byte) error {
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return err
	}
	tmp, err := os.CreateTemp(dir, "."+filepath.Base(path)+".*.tmp")
	if err != nil {
		return err
	}
	tmpName := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
		return err
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpName)
		return err
	}
	return os.Rename(tmpName, path)
}

func writeJSONFile(path string, v any) error {
	data, err := json.MarshalIndent(v, "", "  ")
	if err != nil {
		return err
	}
	data = append(data, '\n')
	return writeAtomicFile(path, data)
}

func fileExists(path string) bool {
	_, err := os.Stat(path)
	return err == nil
}

func fileSize(path string) int {
	info, err := os.Stat(path)
	if err != nil {
		return 0
	}
	return int(info.Size())
}

func formatSRTTime(seconds float64) string {
	totalMillis := int(seconds*1000 + 0.5)
	hours := totalMillis / 3600000
	totalMillis %= 3600000
	minutes := totalMillis / 60000
	totalMillis %= 60000
	secs := totalMillis / 1000
	millis := totalMillis % 1000
	return fmt.Sprintf("%02d:%02d:%02d,%03d", hours, minutes, secs, millis)
}
